#!/usr/bin/env Rscript
# parse-rcmdcheck.R — run rcmdcheck and emit a classified-issues JSON.
#
# Output to stdout (one JSON object):
#   {
#     "errors":   [{...}],
#     "warnings": [{...}],
#     "notes":    [{...}],
#     "summary":  {"errors": N, "warnings": N, "notes": N},
#     "auto_fix":  ["fix_non_ascii", ...],   # unique fixers to run
#     "ambiguous": [{stage, severity, type, message, location}]
#   }
#
# Each issue:
#   { severity, type, message, location, auto_fix }
# `auto_fix` is the name of a fixer in auto-fixers.R, or null if AMBIGUOUS.
#
# Usage:
#   Rscript parse-rcmdcheck.R run   <pkg_dir> [--with-examples]
#                                   [--cache-dir DIR --ts STAMP]
#   Rscript parse-rcmdcheck.R parse <rds_file>
#
# Cache mode (--cache-dir + --ts <stamp>):
#   Writes <DIR>/<stamp>.log (raw stdout+stderr from rcmdcheck),
#          <DIR>/<stamp>.rds (rcmdcheck result object),
#          <DIR>/<stamp>.classified.json (parser output, also stdout).
#   The agent should Read the .log file rather than re-running.
#
# Conservative rule: anything that doesn't match a known auto-fixable
# pattern is AMBIGUOUS (auto_fix = null).

suppressWarnings(suppressMessages({
  ok_jsonlite <- requireNamespace("jsonlite", quietly = TRUE)
  ok_rcmdcheck <- requireNamespace("rcmdcheck", quietly = TRUE)
}))
if (!ok_jsonlite) {
  message("ERROR: jsonlite required")
  quit(status = 2L, save = "no")
}

# ---- classifier rules -----------------------------------------------------

classify_one <- function(text, severity) {
  text <- as.character(text)
  joined <- paste(text, collapse = " ")
  rules <- list(
    list(
      type = "non_ascii",
      pattern = "non-ASCII",
      auto_fix = "fix_non_ascii"
    ),
    list(
      type = "encoding_missing",
      pattern = "(Encoding not declared|no Encoding field)",
      auto_fix = "fix_encoding_declaration"
    ),
    list(
      type = "code_doc_mismatch",
      pattern = "code/documentation mismatches?",
      auto_fix = "fix_document"
    ),
    list(
      type = "stale_rd",
      pattern = "Rd files? are out of date",
      auto_fix = "fix_document"
    ),
    list(
      type = "undocumented_args",
      pattern = "Undocumented arguments?",
      auto_fix = NA_character_
    ),
    list(
      type = "missing_return",
      pattern = "(Missing|Undocumented) return value",
      auto_fix = NA_character_
    ),
    list(
      type = "examples_too_slow",
      pattern = "examples? .* > 5 ?seconds?",
      auto_fix = NA_character_
    ),
    list(
      type = "examples_failed",
      pattern = "Examples? .* failed",
      auto_fix = NA_character_
    ),
    list(
      type = "test_failed",
      pattern = "(Test failures|Tests? .* failed)",
      auto_fix = NA_character_
    )
  )
  hit <- NULL
  for (r in rules) {
    if (grepl(r$pattern, joined, ignore.case = TRUE, perl = TRUE)) {
      hit <- r
      break
    }
  }
  if (is.null(hit)) {
    return(list(
      severity = severity,
      type = "unknown",
      message = joined,
      location = NA_character_,
      auto_fix = NA_character_
    ))
  }
  loc <- extract_location(joined)
  list(
    severity = severity,
    type = hit$type,
    message = joined,
    location = loc,
    auto_fix = hit$auto_fix
  )
}

extract_location <- function(text) {
  m <- regmatches(
    text,
    regexpr("\\b(R|man|tests|inst)/[^[:space:]:,]+(:[0-9]+)?", text)
  )
  if (length(m) == 0L || identical(m, character(0))) {
    NA_character_
  } else {
    m[[1L]]
  }
}

classify <- function(items, severity) {
  if (length(items) == 0L) {
    return(list())
  }
  lapply(items, classify_one, severity = severity)
}

# ---- output assembly ------------------------------------------------------

classified_payload <- function(check) {
  errors   <- classify(check$errors,   "ERROR")
  warnings <- classify(check$warnings, "WARNING")
  notes    <- classify(check$notes,    "NOTE")

  all_issues <- c(errors, warnings, notes)
  fixers <- vapply(all_issues, function(x) {
    if (is.na(x$auto_fix)) {
      ""
    } else {
      x$auto_fix
    }
  }, character(1))
  fixers <- unique(fixers[fixers != ""])

  ambiguous <- Filter(function(x) is.na(x$auto_fix), all_issues)
  ambiguous <- lapply(ambiguous, function(x) {
    list(
      stage = "rcmdcheck",
      severity = x$severity,
      type = x$type,
      message = x$message,
      location = x$location
    )
  })

  list(
    errors = errors,
    warnings = warnings,
    notes = notes,
    summary = list(
      errors = length(errors),
      warnings = length(warnings),
      notes = length(notes)
    ),
    auto_fix = fixers,
    ambiguous = ambiguous
  )
}

emit_result <- function(check) {
  out <- classified_payload(check)
  cat(jsonlite::toJSON(out, auto_unbox = TRUE, null = "null"), "\n", sep = "")
}

# ---- CLI -------------------------------------------------------------------

args <- commandArgs(trailingOnly = TRUE)
if (length(args) < 2L) {
  message("Usage: parse-rcmdcheck.R <run|parse> <pkg_dir|rds_file> [opts]")
  quit(status = 2L, save = "no")
}
mode <- args[[1L]]
target <- args[[2L]]

opt_with_examples <- "--with-examples" %in% args
get_opt <- function(name) {
  i <- which(args == name)
  if (length(i) == 0L || i + 1L > length(args)) {
    NULL
  } else {
    args[[i + 1L]]
  }
}
opt_cache_dir <- get_opt("--cache-dir")
opt_ts <- get_opt("--ts")

if (mode == "run") {
  if (!ok_rcmdcheck) {
    message("ERROR: rcmdcheck required")
    quit(status = 2L, save = "no")
  }
  # Fast pass by default: skip examples + vignettes + tests so the stage
  # finishes in seconds. With --with-examples, run the full --as-cran.
  rc_args <- if (opt_with_examples) {
    c("--no-manual", "--as-cran")
  } else {
    c("--no-manual", "--as-cran",
      "--no-examples", "--no-vignettes", "--no-tests",
      "--no-build-vignettes", "--ignore-vignettes")
  }
  if (!is.null(opt_cache_dir) && !is.null(opt_ts)) {
    dir.create(opt_cache_dir, recursive = TRUE, showWarnings = FALSE)
    log_path <- file.path(opt_cache_dir, paste0(opt_ts, ".log"))
    rds_path <- file.path(opt_cache_dir, paste0(opt_ts, ".rds"))
    json_path <- file.path(opt_cache_dir, paste0(opt_ts, ".classified.json"))
    # Capture all rcmdcheck output to log_path; result object to rds_path.
    log_con <- file(log_path, open = "wt")
    sink(log_con, type = "output", split = FALSE)
    sink(log_con, type = "message")
    on.exit({
      sink(type = "message")
      sink(type = "output")
      close(log_con)
    }, add = TRUE)
    check <- rcmdcheck::rcmdcheck(
      path = target, args = rc_args, quiet = FALSE, error_on = "never"
    )
    saveRDS(check, rds_path)
    sink(type = "message")
    sink(type = "output")
    close(log_con)
    on.exit()
    # Re-open log to append a small footer so the agent knows it's complete.
    cat("\n--- rcmdcheck finished ---\n", file = log_path, append = TRUE)
    # Emit JSON to both stdout and the cache file.
    json_text <- jsonlite::toJSON(
      classified_payload(check), auto_unbox = TRUE, null = "null"
    )
    writeLines(json_text, json_path)
    cat(json_text, "\n", sep = "")
  } else {
    check <- rcmdcheck::rcmdcheck(
      path = target, args = rc_args, quiet = TRUE, error_on = "never"
    )
    emit_result(check)
  }
} else if (mode == "parse") {
  check <- readRDS(target)
  emit_result(check)
} else {
  message(sprintf("Unknown mode: %s", mode))
  quit(status = 2L, save = "no")
}

