purrr_fns <- getNamespaceExports("purrr")
files <- list.files("R", full.names=TRUE, pattern="\\.R$")
for (f in files) {
  lines <- readLines(f)
  for (fn in purrr_fns) {
    pat <- paste0("(?<![a-zA-Z0-9_:])", fn, "\\s*\\(")
    hits <- grep(pat, lines, perl=TRUE, value=TRUE)
    hits <- hits[!grepl("purrr::", hits) & !grepl("^\\s*#", hits)]
    if (length(hits) > 0) {
      cat(basename(f), ":", fn, "-", length(hits), "calls\n")
    }
  }
}' 2>/dev/null

