Rscript -e 'options(warn=-1)
pkgs <- c("dada2", "divent", "purrr")
files <- list.files("tests/testthat", full.names=TRUE, pattern="\\.R$")
results <- list()
for (pkg in pkgs) {
  fns <- getNamespaceExports(pkg)
  fns <- fns[!grepl("^%", fns)]
  for (f in files) {
    lines <- readLines(f)
    for (fn in fns) {
      pat <- paste0("(?<![a-zA-Z0-9_:])", fn, "\\s*\\(")
      hits <- grep(pat, lines, perl=TRUE)
      hits <- hits[!grepl(paste0(pkg, "::"), lines[hits]) & !grepl("^\\s*#", lines[hits])]
      if (length(hits) > 0) {
        results[[length(results)+1]] <- paste0("[", pkg, "] ", basename(f), ":", hits[1], " : ", fn)
      }
    }
  }
}
if (length(results) > 0) cat(paste(results, collapse="\n"), "\n") else cat("All clear\n")
' 2>/dev/null

Rscript -e 'options(warn=-1)
# Check that library(dada2) appears before the bare calls
for (f in c("tests/testthat/test_blast.R", "tests/testthat/test_targets.R")) {
  lines <- readLines(f)
  lib_line <- grep("^library\\(dada2\\)", lines)
  bare_lines <- grep("derepFastq\\s*\\(|\\bdada\\s*\\(", lines)
  bare_lines <- bare_lines[!grepl("dada2::", lines[bare_lines]) & !grepl("^\\s*#", lines[bare_lines])]
  if (length(lib_line) && (length(bare_lines) == 0 || all(bare_lines > lib_line))) {
    cat(basename(f), ": OK (library at line", lib_line, "before bare calls)\n")
  } else {
    cat(basename(f), ": PROBLEM\n")
  }
}' 2>/dev/null
